{ title: "В аптеке из-за головной боли", scene: "Вы заходите в аптеку во Франкфурте, потому что у вас болит голова. Нужно объяснить симптом и спросить, как принимать лекарство.", lines: [{ who: "them", de: "Guten Tag, wie kann ich Ihnen helfen?", ru: "Добрый день, как я могу вам помочь?" }, { who: "you", de: "Guten Tag, ich habe Kopfschmerzen.", ru: "Добрый день, у меня болит голова." }, { who: "them", de: "Haben Sie auch Fieber?", ru: "У вас также есть температура?" }, { who: "you", de: "Nein, kein Fieber.", ru: "Нет, температуры нет." }, { who: "them", de: "Brauchen Sie Tabletten?", ru: "Вам нужны таблетки?" }, { who: "you", de: "Ja, bitte.", ru: "Да, пожалуйста." }, { who: "them", de: "Nehmen Sie eine Tablette mit Wasser.", ru: "Принимайте одну таблетку с водой." }, { who: "you", de: "Wie oft nehme ich das?", ru: "Как часто это принимать?" }, { who: "them", de: "Maximal dreimal am Tag.", ru: "Максимум три раза в день." }, { who: "you", de: "Brauche ich ein Rezept?", ru: "Мне нужен рецепт?" }, { who: "them", de: "Nein, das ist ohne Rezept.", ru: "Нет, это без рецепта." }, { who: "you", de: "Danke für Ihre Hilfe.", ru: "Спасибо за вашу помощь." }] },
{ title: "Небольшой разговор с местным жителем", scene: "Вы сидите в поезде из Кёльна в Дюссельдорф. Сосед замечает вашу карту города, и начинается дружелюбный разговор.", lines: [{ who: "them", de: "Reisen Sie durch Deutschland?", ru: "Вы путешествуете по Германии?" }, { who: "you", de: "Ja, ich bin im Urlaub.", ru: "Да, я в отпуске." }, { who: "them", de: "Woher kommen Sie?", ru: "Откуда вы?" }, { who: "you", de: "Ich komme aus Russland.", ru: "Я из России." }, { who: "them", de: "Und wie gefällt Ihnen Deutschland?", ru: "И как вам нравится Германия?" }, { who: "you", de: "Mir gefällt Deutschland sehr gut.", ru: "Мне очень нравится Германия." }, { who: "them", de: "Welche Stadt besuchen Sie heute?", ru: "Какой город вы посещаете сегодня?" }, { who: "you", de: "Heute besuche ich Düsseldorf.", ru: "Сегодня я посещаю Дюссельдорф." }, { who: "them", de: "Das ist eine schöne Stadt.", ru: "Это красивый город." }, { who: "you", de: "Haben Sie eine Empfehlung?", ru: "У вас есть рекомендация?" }, { who: "them", de: "Gehen Sie am Rhein spazieren.", ru: "Погуляйте у Рейна." }, { who: "you", de: "Danke, das mache ich.", ru: "Спасибо, я так и сделаю." }] }
